mapper.select:
select source_file_id, file_path, chunk_index, chunk_text, is_verbatim from source_file_chunks where file_path in
#{filePath}
order by file_path, chunk_index

with query as ( select plainto_tsquery(cast(#{tsConfig} as regconfig), #{question}) as tsq ) select null::bigint as source_id, concat(sfc.file_path, '#', sfc.chunk_index) as item_key, sfc.file_path as concept_id, sfc.file_path as title, sfc.chunk_text as content, concat( '{"filePath":"', replace(coalesce(sfc.file_path, ''), '"', '\"'), '","chunkIndex":', sfc.chunk_index, ',"verbatim":', sfc.is_verbatim, '}' ) as metadata_json, array[sfc.file_path]::text[] as source_paths, sfc.chunk_index, sfc.is_verbatim as verbatim, ts_rank_cd(sfc.search_tsv, query.tsq)
+ case when sfc.file_path_norm like #{likeToken} then 1.5 else 0 end + case when lower(sfc.chunk_text) like #{likeToken} then 3.0 else 0 end
+ case when lower(sfc.chunk_text) like #{assignmentToken} then 4.0 else 0 end
as score from source_file_chunks sfc cross join query where sfc.search_tsv @@ query.tsq
or sfc.file_path_norm like #{likeToken} or lower(sfc.chunk_text) like #{likeToken}
order by score desc, sfc.indexed_at desc, sfc.file_path asc, sfc.chunk_index asc limit #{limit}
